173	// validateSkillName rejects names that could escape the destination tree.
174	func validateSkillName(name string) error {
175		if name == "" || name == "." || name == ".." {
176			return fmt.Errorf("skills.Install: invalid skill name %q", name)
177		}
178		if strings.ContainsAny(name, `/\`) {
179			return fmt.Errorf("skills.Install: skill name contains path separator: %q", name)
180		}
181		if filepath.IsAbs(name) {
182			return fmt.Errorf("skills.Install: skill name is absolute: %q", name)
183		}
184		if strings.Contains(name, "..") {
185			return fmt.Errorf("skills.Install: skill name contains parent reference: %q", name)
186		}
187		return nil
188	}
