13	// AuditInstalledEntry checks one installed package entry for plugin issues.
14	func AuditInstalledEntry(entry InstalledEntry, fallback *Package) []ValidationIssue {
15		var issues []ValidationIssue
16		root := installedRootPath(entry)
17		if root == "" {
18			issues = append(issues, ValidationIssue{Message: fmt.Sprintf("installed entry %q has no recorded plugin root", entry.Name)})
19			return issues
20		}
21	
22		issues = append(issues, auditRecordedFiles(entry)...)
23	
24		manifest, manifestMissing, manifestIssues := loadPackageDefinitionForAudit(root, fallback)
25		issues = append(issues, manifestIssues...)
26	
27		if manifestMissing {
28			issues = append(issues, ValidationIssue{
29				Path:    filepath.Join(root, "package.yaml"),
30				Message: "missing package.yaml",
31			})
32		}
33	
34		if manifest == nil {
35			manifest = &Package{}
36		}
37	
38		issues = append(issues, ValidatePackageStructure(root, manifest)...)
39		return issues
