51	func loadPackageDefinitionForAudit(root string, fallback *Package) (*Package, bool, []ValidationIssue) {
52		manifest, manifestMissing, issues, err := LoadPackageManifestWithFallback(root, fallback)
53		if err == nil || os.IsNotExist(err) {
54			// Report validation issues even when package is valid, so audit shows schema problems.
55			return manifest, manifestMissing, issues
56		}
57	
58		// If a partial package was returned (YAML parsed but validation issues exist),
59		// return it with the issues so structural audits can proceed.
60		if manifest != nil {
61			return manifest, false, issues
62		}
63	
64		if len(issues) == 0 {
65			issues = append(issues, ValidationIssue{Path: filepath.Join(root, "package.yaml"), Message: err.Error()})
66		}
67		return manifest, false, issues
