96	func auditRecordedFiles(entry InstalledEntry) []ValidationIssue {
97		var issues []ValidationIssue
98		seen := map[string]bool{}
99		recordedPaths := append([]string(nil), entry.Files...)
100		if root := installedRootPath(entry); root != "" {
101			recordedPaths = append(recordedPaths, root)
102		}
103		for _, recorded := range recordedPaths {
104			path := ExpandHome(recorded)
105			if path == "" || seen[path] {
106				continue
107			}
108			seen[path] = true
109			info, err := os.Lstat(path)
110			if err != nil {
111				if os.IsNotExist(err) {
112					// Pre-migration entries whose paths begin with ~ are outside the
113					// project root; treat missing paths as no-op (no issue raised).
114					if strings.HasPrefix(recorded, "~") {
115						continue
116					}
117					issues = append(issues, ValidationIssue{Path: path, Message: "missing recorded file or symlink"})
118					continue
119				}
120				issues = append(issues, ValidationIssue{Path: path, Message: err.Error()})
121				continue
122			}
123			if info.Mode()&os.ModeSymlink == 0 {
124				continue
125			}
126	
127			target, err := os.Readlink(path)
128			if err != nil {
129				issues = append(issues, ValidationIssue{Path: path, Message: fmt.Sprintf("broken symlink: %v", err)})
130				continue
131			}
132			if !filepath.IsAbs(target) {
133				target = filepath.Join(filepath.Dir(path), target)
134			}
135			if _, err := os.Stat(target); err != nil {
136				issues = append(issues, ValidationIssue{Path: path, Message: fmt.Sprintf("broken symlink target %q: %v", target, err)})
137			}
138		}
139		return issues
140	}
