191	func collectSkillRoots(root string, pkg *Package) []string {
192		seen := map[string]bool{}
193		var roots []string
194	
195		add := func(candidate string) {
196			if strings.TrimSpace(candidate) == "" {
197				return
198			}
199			abs := candidate
200			if resolved, err := filepath.EvalSymlinks(candidate); err == nil && resolved != "" {
201				abs = resolved
202			} else if resolved, err := filepath.Abs(candidate); err == nil && resolved != "" {
203				abs = resolved
204			}
205			if seen[abs] {
206				return
207			}
208			if _, err := os.Stat(candidate); err != nil {
209				return
210			}
211			seen[abs] = true
212			roots = append(roots, candidate)
213		}
214	
215		for _, mapping := range pkg.Install.Skills {
216			sourceRoot := filepath.Join(root, filepath.FromSlash(mapping.Source))
217			add(sourceRoot)
218	
219			cleanSource := filepath.Clean(filepath.FromSlash(mapping.Source))
220			switch cleanSource {
221			case filepath.Join(".agents", "skills"), filepath.Join(".claude", "skills"):
222				add(filepath.Join(root, "skills"))
223			}
224		}
225	
226		return roots
227	}
