229	func collectIgnoredBrokenSymlinkPaths(root string, pkg *Package) map[string]bool {
230		ignored := make(map[string]bool)
231		for _, mapping := range pkg.Install.Skills {
232			cleanSource := filepath.Clean(filepath.FromSlash(mapping.Source))
233			switch cleanSource {
234			case filepath.Join(".agents", "skills"), filepath.Join(".claude", "skills"):
