326		info, err := os.Stat(path)
327		if err != nil {
328			return []ValidationIssue{{Path: path, Message: err.Error()}}
329		}
330		if info.IsDir() {
331			return []ValidationIssue{{Path: path, Message: "expected executable file, found directory"}}
332		}
333		if info.Mode()&0111 == 0 {
334			return []ValidationIssue{{Path: path, Message: "file lost execute permission"}}
335		}
336		return nil
337	}
